interface Props{
  companyName: string;
  ticker: string;
  price: number;
}

const Card = ({companyName, ticker, price}: Props) => {
  return (
    <div className="card">
        <img src="https://images.unsplash.com/photo-1612428978260-2b9c7df20150?ixlib=rb-4.0.3&auto=format&fit=crop&w=800&q=60" alt="Image" />
    
        <div className="details">
            <h2>{companyName} ({ticker})</h2>
            <p>${price}</p>
        </div>

        <div>
            <p className="infon">
                This is a sample description for the card component. It provides additional information about the item displayed in the card.
            </p>
        </div>

    </div>
  )
}

export default Card
